#!/usr/bin/perl
use strict;
use warnings;

my $filename = $ARGV[0];
die "Usage: $0 <file>\n" unless defined $filename;

open(my $fh, '<', $filename) or die "Cannot open file: $!";

while (my $line = <$fh>) {
    chomp $line;
    my @fields = split /,/, $line;

    # Ensure we have at least 2 fields and age is numeric > 30
    if (@fields >= 2 && ($fields[1] + 0) > 30) {
        print "$line\n";
    }
}

close($fh);
